const launch = $('Get Post-Launch Launches').item.json;
const signals = $('Fetch Week Signals').all().map(i => i.json);

const weekNumber = (launch.weeks_tracked || 0) + 1;

// Compute messaging drift
const messagingSignals = signals.filter(s => s.signal_type === 'messaging');
const positioningSignals = signals.filter(s => s.signal_type === 'positioning');
const homepageSignals = signals.filter(s => s.signal_type === 'messaging' || s.signal_type === 'positioning');

// Drift scoring: more competitor activity = higher drift
const messagingDrift = Math.min(100, messagingSignals.length * 15 + positioningSignals.length * 10);
const homepageChanges = homepageSignals.length;
const competitorResponses = signals.length;

// Determine momentum
let momentum = 'holding';
if (messagingDrift < 20 && competitorResponses < 3) momentum = 'strong';
else if (messagingDrift > 60 || competitorResponses > 10) momentum = 'fading';
else if (positioningSignals.length > 3) momentum = 'pivoted';

// Competitor reactions
const reactions = {};
for (const s of signals) {
  if (!reactions[s.company_name]) reactions[s.company_name] = [];
  reactions[s.company_name].push(s.title);
}
const competitorReactions = Object.entries(reactions).map(([comp, titles]) => ({
  competitor: comp,
  reaction: titles.slice(0, 2).join('; '),
  severity: titles.length > 3 ? 'high' : titles.length > 1 ? 'medium' : 'low'
}));

// Recommendations
const recommendations = [];
if (messagingDrift > 50) recommendations.push({ label: 'Update Messaging', detail: 'Significant competitor messaging activity detected. Review and adjust positioning.' });
if (momentum === 'fading') recommendations.push({ label: 'Reinforce Launch', detail: 'Launch momentum is fading. Consider additional promotion or content push.' });
if (competitorResponses > 5) recommendations.push({ label: 'Monitor Responses', detail: `${competitorResponses} competitor signals this week. Track for counter-positioning.` });

// Brief content
const briefTitle = `Decay Report — Week ${weekNumber}`;
const briefMd = `# ${briefTitle}\n**Launch:** ${launch.launch_name}\n**Week:** ${weekNumber} of 4\n**Momentum:** ${momentum}\n\n---\n\n## Messaging Drift: ${messagingDrift}%\n## Homepage Changes: ${homepageChanges}\n## Competitor Responses: ${competitorResponses}\n\n## Competitor Reactions\n${competitorReactions.map(cr => `- **${cr.competitor}**: ${cr.reaction} [${cr.severity}]`).join('\n') || 'No notable reactions'}\n\n## Recommendations\n${recommendations.map(r => `- **${r.label}**: ${r.detail}`).join('\n') || 'Stay the course.'}\n\n---\n*Generated by Signal Plane Launch Operations*`;

return [{
  json: {
    launch_id: launch.launch_id,
    user_id: launch.user_id,
    week_number: weekNumber,
    messaging_drift: messagingDrift,
    homepage_changes: homepageChanges,
    competitor_responses: competitorResponses,
    momentum: momentum,
    competitor_reactions_json: JSON.stringify(competitorReactions),
    recommendations_json: JSON.stringify(recommendations),
    brief_title: briefTitle,
    brief_md: briefMd,
    brief_json: JSON.stringify({ momentum, drift: messagingDrift, reactions: competitorReactions }),
    signal_count: signals.length,
    days_since_launch: Math.round((Date.now() - new Date(launch.actual_launch_date).getTime()) / (1000 * 60 * 60 * 24))
  }
}];
